31	TEST_CASE("write through SimpleMemory shows up on disk through MmapBacking")
32	{
33	  const auto path = unique_tmp_path("write");
34	  constexpr std::size_t kSize = 0x1000;
35	  constexpr uint64_t kBase = 0x1000;
36	
37	  MmapBacking backing(path, kSize);
38	  SimpleMemory<32> mem{
39	    "mem", MemoryRegion{kBase, kBase + kSize - 1},
40	    MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
41	                 SimpleMemory<32>::INVALID_ADDRESS},
42	    backing.span()};
43	
44	  std::array<uint8_t, 4> bytes{0xde, 0xad, 0xbe, 0xef};
45	  tlm::tlm_generic_payload gp;
46	  gp.set_command(tlm::TLM_WRITE_COMMAND);
47	  gp.set_address(kBase + 0x100);
48	  gp.set_data_ptr(bytes.data());
49	  gp.set_data_length(bytes.size());
50	  gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
51	  sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
52	  mem.b_transport(gp, delay);
53	  REQUIRE(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
54	
55	  // Independent reader: open the file fresh and mmap it.
56	  const int fd = ::open(path.c_str(), O_RDONLY);
57	  REQUIRE(fd >= 0);
58	  void* p = ::mmap(nullptr, kSize, PROT_READ, MAP_SHARED, fd, 0);
59	  REQUIRE(p != MAP_FAILED);
60	  auto* file_bytes = static_cast<const uint8_t*>(p);
