14	template<std::size_t BusWidth>
15	class SimpleMemory : public sc_core::sc_module
16	{
17	public:
18	  static constexpr uint64_t INVALID_ADDRESS = 0xffffffffffffffff;
19	
20	  const MemoryRegion region;
21	  const MemoryRegion alias_region;
22	
23	private:
24	  std::vector<uint8_t> owned_storage_;
25	
26	public:
27	  std::span<uint8_t> data;
28	
29	  unsigned latency = 1;
30	  tlm_utils::simple_target_socket<SimpleMemory<BusWidth>, BusWidth> socket{
31	    "tsck"};
32	
33	  // If `external_buffer` is empty, owned storage of region size is allocated.
34	  // Otherwise the buffer must outlive this object and be at least region size;
35	  // the size mismatch is rejected before any allocation.
36	  SimpleMemory(const sc_core::sc_module_name& name,
37	               const MemoryRegion& region,
38	               const MemoryRegion& alias_region = {INVALID_ADDRESS,
39	                                                   INVALID_ADDRESS},
40	               std::span<uint8_t> external_buffer = {})
41	      : sc_core::sc_module{name},
42	        region(region),
43	        alias_region(alias_region),
44	        owned_storage_(owned_size(external_buffer, region)),
45	        data(external_buffer.empty() ? std::span<uint8_t>{owned_storage_}
46	                                     : external_buffer)
47	  {
48	    this->socket.register_b_transport(this, &SimpleMemory::b_transport);
49	  }
50	
51	  void b_transport(tlm::tlm_generic_payload& trans, sc_core::sc_time& delay)
52	  {
53	    auto cycles = handle_trans(trans);
54	    if (trans.get_response_status() == tlm::TLM_INCOMPLETE_RESPONSE)
55	      trans.set_response_status(tlm::TLM_OK_RESPONSE);
56	    delay += sc_core::sc_time(cycles, sc_core::SC_NS);
57	  }
58	
59	private:
60	  static auto owned_size(std::span<uint8_t> external_buffer,
61	                         const MemoryRegion& region) -> std::size_t
62	  {
63	    const auto required = region.end_address - region.base_address;
64	    if (external_buffer.empty())
65	      return required;
66	    if (external_buffer.size() < required) [[unlikely]]
67	      throw std::runtime_error(
68	        "SimpleMemory external_buffer smaller than region size");
69	    return 0;
70	  }
71	
72	  auto handle_trans(tlm::tlm_generic_payload& trans) -> unsigned
73	  {
74	    const auto addr = trans.get_address();
75	    const auto len = trans.get_data_length();
76	    const auto ptr = trans.get_data_ptr();
77	    const auto byte_enable_len = trans.get_byte_enable_length();
78	    const auto byte_enable_ptr = trans.get_byte_enable_ptr();
79	
80	    spdlog::debug("mem: {}, addr={:#x}, len={}",
81	                  trans.is_read() ? "read" : "write", addr, len);
82	
83	    uint64_t offset;
84	    if (region.contains({addr, addr + len})) [[likely]] {
85	      offset = addr - this->region.base_address;
86	    } else if (alias_region.contains({addr, addr + len})) {
87	      offset = addr - this->alias_region.base_address;
88	    } else {
89	      spdlog::error(
90	        "transaction is out of bounds of memory region [{:#x}-{:#x}]",
91	        this->region.base_address, this->region.end_address);
92	      trans.set_response_status(tlm::TLM_ADDRESS_ERROR_RESPONSE);
93	      return latency;
94	    }
95	    const auto buf = std::span{ptr, ptr + len};
96	    if (trans.is_read()) [[likely]] {
97	      std::copy_n(this->data.begin() + offset, len, buf.begin());
98	      return latency;
99	    }
100	
101	    if (!trans.is_write()) [[unlikely]] {
102	      throw std::runtime_error("unimplemented");
103	    }
104	
105	    if (byte_enable_len == 0) [[likely]] {
106	      std::copy_n(buf.begin(), len, this->data.begin() + offset);
107	      return latency;
108	    }
109	
110	    // AXI/AHB may split an un-aligned write into multiple aligned writes
111	    // with a byte-enable mask.
112	    assert(byte_enable_len == len);
113	    for (unsigned i = 0; i < len; i++) {
114	      if (byte_enable_ptr[i] == 0xff)
115	        this->data[offset + i] = buf[i];
116	    }
117	    return latency;
118	  }
119	};
