10	#include <doctest.h>
11	
12	#include <cstdint>
13	
14	constexpr uint64_t kNdsHvmBase = 0x90000000ULL;
15	
16	TEST_CASE("RAM region covers QEMU virt RAM base 0x80000000")
17	{
18	  CHECK(static_cast<uint64_t>(RAM_END) >= 0x80000000ULL);
19	}
20	
21	TEST_CASE("RAM region does not collide with NDS_HVM_BASE")
22	{
23	  CHECK(static_cast<uint64_t>(RAM_END) < kNdsHvmBase);
24	}
25	
26	TEST_CASE("RAM region does not collide with HART0 ILM peripheral")
27	{
28	  CHECK(static_cast<uint64_t>(RAM_END) < static_cast<uint64_t>(HART0_ILM_BASE));
