35	{
36	  using PLATFORM = Platform<platform_config<CPU>>;
37	  static constexpr bool is_axi = (CPU::SYSTEM_BUS_TYPE == BusTypes::AXI);
38	  static constexpr auto bus_width = PLATFORM::data_width;
39	
40	  // Helper: create an AXI→TLM bridge, bind clock, connect initiator BFM
41	  auto make_axi_to_tlm(const char* name, auto& bfm_socket)
42	    -> std::unique_ptr<axi_to_tlm_bridge<bus_width>>
43	  {
44	    auto bridge = std::make_unique<axi_to_tlm_bridge<bus_width>>(name);
45	    bridge->pe.clk_i.bind(platform.clk);
46	    bfm_socket.bind(bridge->axi_tsck);
47	    return bridge;
48	  }
49	
50	  // Helper: create a TLM→AXI bridge, bind clock, connect target BFM
51	  auto make_tlm_to_axi(const char* name, auto& bfm_socket)
52	    -> std::unique_ptr<tlm_to_axi_bridge<bus_width>>
53	  {
54	    auto bridge = std::make_unique<tlm_to_axi_bridge<bus_width>>(name);
55	    bridge->pe.clk_i.bind(platform.clk);
56	    bridge->axi_isck.bind(bfm_socket);
57	    return bridge;
58	  }
