103	  Simulator(const sc_core::sc_module_name& name,
104	            std::span<uint8_t> ram_buffer = {})
105	      : sc_core::sc_module{name},
106	        platform("platform", ram_buffer),
107	        dtm(platform.dtm)
108	  {
109	    cpu.bind(platform.clk, platform.resetn, platform.reset_vector,
110	             platform.dmi_signals, platform.wfi_signal, platform.int_trigger);
111	
112	    // --- CPU memory BFM → interconnect ---
113	    if constexpr (is_axi) {
114	      mem_bridge = make_axi_to_tlm("mem_bridge", cpu.mem_bfm.isckt);
115	      platform.interconnect.bind_initiator(mem_bridge->tlm_isck);
116	    } else {
117	      platform.interconnect.bind_initiator(cpu.mem_bfm.isckt);
118	    }
119	
120	    // --- CPU MMIO BFM → interconnect ---
121	    if constexpr (requires { cpu.mmio_bfm; }) {
122	      if constexpr (is_axi) {
123	        mmio_bridge = make_axi_to_tlm("mmio_bridge", cpu.mmio_bfm.isckt);
124	        platform.interconnect.bind_initiator(mmio_bridge->tlm_isck);
125	      } else {
126	        platform.interconnect.bind_initiator(cpu.mmio_bfm.isckt);
127	      }
128	    }
129	
130	    // --- CPU HVM subordinate port ---
131	    if constexpr (requires { cpu.hvm_bfm; }) {
132	      if constexpr (is_axi) {
133	        hvm_bridge = make_tlm_to_axi("hvm_bridge", cpu.hvm_bfm.tsckt);
134	        platform.interconnect.bind_target(
135	          hvm_bridge->tlm_tsck,
136	          {CPU::NDS_HVM_BASE,
137	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
138	      } else {
139	        platform.interconnect.bind_target(
140	          cpu.hvm_bfm.tsckt,
141	          {CPU::NDS_HVM_BASE,
142	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
143	      }
144	      platform.custom_master.hvm_base = CPU::NDS_HVM_BASE;
145	    }
146	
147	    // --- CPU slave port ---
148	    if constexpr (requires { cpu.slv_bfm; }) {
149	      if constexpr (is_axi) {
150	        slv_bridge = make_tlm_to_axi("slv_bridge", cpu.slv_bfm.tsckt);
151	        platform.interconnect.bind_target(slv_bridge->tlm_tsck,
152	                                          {HART0_ILM_BASE, HART0_DLM_END});
153	      } else {
154	        platform.interconnect.bind_target(cpu.slv_bfm.tsckt,
155	                                          {HART0_ILM_BASE, HART0_DLM_END});
156	      }
157	      platform.custom_master.ilm_base = HART0_ILM_BASE;
158	      platform.custom_master.dlm_base = HART0_DLM_BASE;
159	    }
160	
161	    // --- CPU sys bus (slave port, 64-bit) → interconnect ---
162	    if constexpr (requires { cpu.sys_bfm; }) {
163	      sys_adapter =
164	        std::make_unique<socket_width_adapter<bus_width, sys_bus_width>>(
165	          "sys_adapter");
166	      sys_bridge =
167	        std::make_unique<tlm_to_axi_bridge<sys_bus_width>>("sys_bridge");
168	      sys_bridge->pe.clk_i.bind(platform.clk);
169	      sys_bridge->axi_isck.bind(cpu.sys_bfm.tsckt);
170	      sys_adapter->isck.bind(sys_bridge->tlm_tsck);
171	      platform.interconnect.bind_target(sys_adapter->tsck,
172	                                        {MLIF_BASE, SLIF_END});
173	    }
174	
175	#if _NDS_IOCP_NUM > 0
176	    iocp_master.protocol_engine.clk_i.bind(platform.clk);
177	    iocp_master.socket.bind(cpu.iocp_bfm.tsckt);
178	#endif // _NDS_IOCP_NUM
179	  }
