190	  // Caller invariant: the CPU must already be out of reset.
191	  void apply_resume_from_qemu(const std::string& path)
192	  {
193	    hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width, PLATFORM::dmi_data_width>
194	      bus{platform.dmi, platform.clk.period()};
195	    hybrid::resume_from_qemu(path, bus);
