198	  // Enables the vsim->QEMU handoff drain. After this is set, run() watches
199	  // committed PCs and on retire of a `csrw 0x7C0, *` exit-trigger drains
200	  // architectural state to `state_out_path` and returns kExitHandoffToQemu.
201	  void enable_hybrid_handoff(const std::string& elf_path,
202	                             const std::string& state_out_path)
203	  {
204	    auto elf = LIEF::ELF::Parser::parse(elf_path);
205	    if (!elf)
206	      throw std::runtime_error(
207	        "enable_hybrid_handoff: failed to parse " + elf_path);
208	
209	    hybrid::CsrTrigger trigger;
210	    for (const auto& seg: elf->segments()) {
211	      if (seg.type() != LIEF::ELF::SEGMENT_TYPES::PT_LOAD) continue;
212	      if ((static_cast<unsigned>(seg.flags()) & 1u) == 0u) continue;  // PF_X
213	      const auto content = seg.content();
214	      const std::span<const uint8_t> bytes{content.data(), content.size()};
215	      trigger.scan_buffer(bytes, seg.virtual_address());
216	    }
217	
218	    hybrid_dmi_bus_ = std::make_unique<
219	      hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width,
220	                            PLATFORM::dmi_data_width>>(platform.dmi,
221	                                                       platform.clk.period());
222	    hybrid_handoff_.emplace(std::move(trigger), *hybrid_dmi_bus_);
223	    hybrid_state_path_ = state_out_path;
224	  }
