238	  void load_elf(const std::string& path)
239	  {
240	    const auto elf = LIEF::ELF::Parser::parse(path);
241	    if (!elf) {
242	      spdlog::critical("Check if it's a valid ELF file path : {}", path);
243	      exit(1);
244	    }
245	
246	    read_elf_into_memory(*elf, xlen_t{0}, platform.main_memory.data);
247	    for (auto& rv: platform.reset_vector)
248	      rv.write(elf->entrypoint());
249	  }
