251	  void set_reset_vector(size_t hart, uint64_t addr)
252	  {
253	    if (hart >= platform.reset_vector.size()) {
254	      spdlog::critical("hart {} out of range (max {})", hart,
255	                       platform.reset_vector.size() - 1);
256	      std::exit(EXIT_FAILURE);
257	    }
258	    platform.reset_vector[hart].write(addr);
259	  }
260	
261	  void load_image(const std::string& path, MEM_TYPE type)
262	  {
263	    switch (type) {
264	    case MEM_TYPE::ILM:
265	      if constexpr (requires { cpu.set_ilm({}); }) {
266	        read_binary_file(path, [this](const auto& data) { cpu.set_ilm(data); });
267	      } else {
268	        throw std::runtime_error(
269	          "CPU does not support ILM - cannot load ILM ROM image");
270	      }
271	      break;
272	
273	    case MEM_TYPE::DLM:
274	      if constexpr (requires { cpu.set_dlm({}); }) {
275	        read_binary_file(path, [this](const auto& data) { cpu.set_dlm(data); });
276	      } else {
277	        throw std::runtime_error(
278	          "CPU does not support DLM - cannot load DLM ROM image");
279	      }
280	      break;
281	
282	    case MEM_TYPE::RAM:
283	      read_binary_file(path, [this](const auto& data) {
284	        if (data.size() > platform.main_memory.data.size())
285	          throw std::runtime_error("RAM image size exceeds main memory size");
286	        std::copy(data.begin(), data.end(), platform.main_memory.data.begin());
287	      });
288	      break;
289	
290	    default:
291	      throw std::runtime_error("Unknown memory type");
292	    }
293	  }
294	
295	  void reset()
296	  {
297	    static constexpr int core_num = CPU::NDS_NHART;
298	    static constexpr int reset_val = (1 << core_num) - 1;
299	
300	    platform.resetn.write(0);
301	    auto saved = context_config;
302	    context_config = {};
303	    this->run(1);
304	    context_config = saved;
305	
306	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
307	      spdlog::info("hart {} reset vector: {:#x}", i,
308	                   (uint64_t) platform.reset_vector[i].read());
309	
310	    platform.resetn.write(reset_val);
311	
312	    if (context_config.continue_from)
313	      restore_context(context_config.dir);
314	  }
315	
316	  int run(const uint64_t max_cycles = std::numeric_limits<uint64_t>::max())
317	  {
318	    auto sa = memzeroed<struct sigaction>();
319	    sa.sa_handler = sigint_handler;
320	    sigemptyset(&sa.sa_mask);
321	
322	    auto oact = memzeroed<struct sigaction>();
323	    if (sigaction(SIGINT, &sa, &oact) == -1)
324	      perror("sigaction");
325	
326	    const auto restore_sigint = std::experimental::scope_exit{[&] {
327	      if (sigaction(SIGINT, &oact, nullptr) == -1)
328	        perror("sigaction");
329	    }};
330	
331	    // wait for debugger connections
332	    while (dtm_debug && !dtm.is_connected()) {
333	      dtm.try_accept_socket();
334	      if (ctrlc != 0) {
335	        return 130;
336	      }
337	      sleep(1);
338	    }
339	
340	    [[maybe_unused]]
341	    bool ctx_resuming = context_config.continue_from;
342	    [[maybe_unused]]
343	    bool ctx_triggered = false;
344	
345	    for (auto n = uint64_t{0}; n < max_cycles; ++n) {
346	
347	      if (ctx_resuming) [[unlikely]] {
348	        // Pull up PLIC interrupt signal at the first cycle of the resume
349	        platform.int_trigger.write(1);
350	        ctx_resuming = false;
351	        ctx_triggered = true;
352	      }
353	
354	      sc_core::sc_start(platform.clk.period());
355	
356	      trace_.on_cycle(cpu);
357	
358	      if (hybrid_handoff_) [[unlikely]] {
359	        if (auto code = check_hybrid_handoff(); code) return *code;
360	      }
361	
362	      if (trace_.pipeview_wants_exit()) {
363	        spdlog::info("Pipeline viewer requested exit (Kanata loop window complete)");
364	        return 0;
365	      }
366	
367	      if (context_config.save_on_wfi && platform.wfi_signal.read() == true)
368	        [[unlikely]]
369	      {
370	        context_config.save(platform, cpu);
371	        spdlog::info("User save context");
372	        return 0;
373	      }
374	
375	      if (ctrlc != 0) {
376	        ctrlc = 0;
377	        spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
378	        trace_.log_committed_pcs(cpu);
379	        return 130;
380	      }
381	
382	      if (ctx_triggered) [[unlikely]] {
383	        // Pull down the interrupt signal after 1 cycle
384	        platform.int_trigger.write(0);
385	        ctx_triggered = false;
386	      }
387	
388	      if (platform.sim_control.exits >= 0) {
389	        spdlog::info("sim_control: got exit {}, stopping",
390	                     platform.sim_control.exits);
391	        spdlog::info("Exit PC: {:x}", get_current_pc());
392	        trace_.log_committed_pcs(cpu);
393	        return platform.sim_control.exits;
394	      }
395	
396	      if (this->cpu.contextp()->gotFinish())
397	        return 0;
398	
399	      spdlog::trace("PC: {:x}", get_current_pc());
400	    }
